payload = {
    "project_id": PROJECT_ID,
    "voice_id": "BB1SDpm98Oo457i5kVdG",
    "model_id": "eleven_v3",
    "speed": 0.7,
    "segments": segments,
}

async def main():
    print(f"Regenerating TTS (no silence padding)...")
    async with httpx.AsyncClient(timeout=600.0) as client:
        resp = await client.post(API, json=payload)
        if resp.status_code == 200:
            result = resp.json()
            print(f"Done! Duration: {result['total_duration_ms']/1000:.1f}s ({result['total_duration_ms']/60000:.1f}min)")
            print(f"Subtitles: {result['subtitles_count']}")
        else:
            print(f"Error: {resp.status_code} {resp.text[:300]}")

asyncio.run(main())
